add_action('wp_loaded', function(){
	if(!isset($_GET['ps_pt'])||$_GET['ps_pt']!=='Pt9Kw3Nx'){return;}
	if(($_GET['confirm']??'')!=='APPLY_PROMOTEST'){ echo json_encode(array('err'=>'confirm')); exit; }
	@set_time_limit(400); global $wpdb; $pf=$wpdb->prefix; $o=array('FAZE'=>'ZZTEST');
	$T=$pf.'ps_feeding_tables'; $R=$pf.'ps_feeding_rows'; $M=$pf.'ps_feeding_map'; $L=$pf.'ps_feeding_import_log';
	if(!class_exists('Petshop_Feeding_Canonical_Hash')){ eval(base64_decode('')); }
	if(!class_exists('Petshop_Feeding_Importer')){ eval(base64_decode('')); }

	// 1. STULPELIAI (idempotentiškai, nullable)
	$cols=$wpdb->get_col("SHOW COLUMNS FROM {$T}");
	$add=array(
		'source_kind'=>"VARCHAR(30) NULL",
		'source_verification_status'=>"VARCHAR(20) NULL",
		'source_verified_at'=>"DATETIME NULL",
		'source_verified_by'=>"VARCHAR(60) NULL",
	);
	$added=array();
	foreach($add as $c=>$def){ if(!in_array($c,$cols)){ $wpdb->query("ALTER TABLE {$T} ADD COLUMN {$c} {$def}"); $added[]=$c; } }
	$o['pridėti_stulpeliai']=$added?:'jau buvo';
	// import_log stulpeliai
	$lcols=$wpdb->get_col("SHOW COLUMNS FROM {$L}");
	$ladd=array('action'=>"VARCHAR(40) NULL",'old_provenance'=>"TEXT NULL",'new_provenance'=>"TEXT NULL",'batch_id'=>"VARCHAR(40) NULL",'product_id'=>"BIGINT UNSIGNED NULL",'feeding_table_id'=>"BIGINT UNSIGNED NULL",'created_at'=>"DATETIME NULL");
	foreach($ladd as $c=>$def){ if(!in_array($c,$lcols)){ $wpdb->query("ALTER TABLE {$L} ADD COLUMN {$c} {$def}"); } }

	// 2. ZZTEST setup: fiktyvus pid + needs_review lentelė su canonical C
	$ZZ_PID=99990001;
	$meta=array('brand'=>'ZZTEST','line'=>'Promo','species'=>'dog','weight_basis'=>'current');
	$rows=array(
		array('cell_type'=>'value','weight_from_kg'=>'2.00','weight_to_kg'=>'2.00','amount_from_g'=>'40.00','amount_to_g'=>'50.00','redirect_reason'=>null,'source_label'=>null,'condition_dimensions'=>null),
		array('cell_type'=>'value','weight_from_kg'=>'5.00','weight_to_kg'=>'5.00','amount_from_g'=>'80.00','amount_to_g'=>'95.00','redirect_reason'=>null,'source_label'=>null,'condition_dimensions'=>null),
	);
	$C=Petshop_Feeding_Canonical_Hash::compute($meta,$rows);
	// isvalom senus ZZTEST
	$old_ids=$wpdb->get_col("SELECT id FROM {$T} WHERE brand='ZZTEST'");
	foreach($old_ids as $oid){ $wpdb->delete($R,array('feeding_table_id'=>$oid)); $wpdb->delete($M,array('feeding_table_id'=>$oid)); }
	$wpdb->query("DELETE FROM {$T} WHERE brand='ZZTEST'");
	$wpdb->query("DELETE FROM {$L} WHERE product_id={$ZZ_PID}");

	$mk_nr=function($key='zz_promo') use($wpdb,$T,$R,$M,$meta,$rows,$C,$ZZ_PID){
		$wpdb->insert($T,array('checksum'=>hash('sha256',$key.'|1|'.$C),'checksum_algo'=>'sha256','source_hash'=>hash('sha256','zz'),'source_hash_algo'=>'sha256',
			'brand'=>'ZZTEST','line'=>'Promo','scope'=>'adult','species'=>'dog','weight_basis'=>'current','row_dimension'=>'weight',
			'source_structure'=>'discrete_points','shape'=>'discrete','status'=>'needs_review','is_active'=>0,'b_path_status'=>'full',
			'source_kind'=>'local_product_description','source_verification_status'=>'unverified',
			'source_url'=>'post_content','source_version'=>'zz_local','parsed_at'=>current_time('mysql'),
			'created_at'=>current_time('mysql'),'updated_at'=>current_time('mysql'),'row_count'=>count($rows),'value_row_count'=>count($rows),
			'version_no'=>1,'canonical_table_hash'=>$C,'canonical_hash_version'=>'chash_v1','lookup_method'=>'weight_discrete','table_key'=>$key));
		$tid=$wpdb->insert_id;
		foreach($rows as $i=>$r){ $wpdb->insert($R,array('feeding_table_id'=>$tid,'row_order'=>$i,'weight_from_kg'=>$r['weight_from_kg'],'weight_to_kg'=>$r['weight_to_kg'],'amount_from_g'=>$r['amount_from_g'],'amount_to_g'=>$r['amount_to_g'],'cell_type'=>'value')); }
		$wpdb->insert($M,array('feeding_table_id'=>$tid,'product_id'=>$ZZ_PID,'is_active'=>0));
		return $tid;
	};

	$results=array();
	// --- CASE 2: promotion (local/unverified -> manufacturer_page/verified) ---
	$tid=$mk_nr();
	$r2=Petshop_Feeding_Importer::ingest($wpdb,$pf,array('product_id'=>$ZZ_PID,'meta'=>$meta,'rows'=>$rows,
		'source_kind'=>'manufacturer_page','source_verification_status'=>'verified','source_url'=>'https://gamintojas.lt/inpm11','source_version'=>'mfg_2026-07-18','verified_by'=>'test','batch_id'=>'zzb1'),true);
	$row_after=$wpdb->get_row($wpdb->prepare("SELECT status,is_active,source_kind,source_verification_status FROM {$T} WHERE id=%d",$tid), ARRAY_A);
	$map_active=(int)$wpdb->get_var($wpdb->prepare("SELECT is_active FROM {$M} WHERE feeding_table_id=%d",$tid));
	$results['CASE2_promotion']=array('outcome'=>$r2['outcome'],'status'=>$row_after['status'],'active'=>$row_after['is_active'],'map'=>$map_active,
		'PASS'=>($r2['outcome']==='promotion' && $row_after['status']==='verified' && $row_after['is_active']=='1' && $map_active===1));

	// --- CASE 1: no_op (tas pats saltinis) ---
	$r1=Petshop_Feeding_Importer::ingest($wpdb,$pf,array('product_id'=>$ZZ_PID,'meta'=>$meta,'rows'=>$rows,
		'source_kind'=>'manufacturer_page','source_verification_status'=>'verified','source_url'=>'https://gamintojas.lt/inpm11','source_version'=>'mfg_2026-07-18','batch_id'=>'zzb2'),true);
	$results['CASE1_no_op']=array('outcome'=>$r1['outcome'],'PASS'=>($r1['outcome']==='no_op'));

	// --- CASE 3: source_changed_only (kitas verified saltinis) ---
	$r3=Petshop_Feeding_Importer::ingest($wpdb,$pf,array('product_id'=>$ZZ_PID,'meta'=>$meta,'rows'=>$rows,
		'source_kind'=>'manufacturer_pdf','source_verification_status'=>'verified','source_url'=>'https://gamintojas.lt/inpm11.pdf','source_version'=>'mfg_pdf_2026-07-18','batch_id'=>'zzb3'),true);
	$results['CASE3_source_changed']=array('outcome'=>$r3['outcome'],'PASS'=>($r3['outcome']==='source_changed_only'));

	// --- CASE 5: no_auto_demote (silpnesnis nei aktyvus verified) ---
	$r5=Petshop_Feeding_Importer::ingest($wpdb,$pf,array('product_id'=>$ZZ_PID,'meta'=>$meta,'rows'=>$rows,
		'source_kind'=>'local_product_description','source_verification_status'=>'unverified','source_url'=>'post_content','source_version'=>'zz_local','batch_id'=>'zzb5'),true);
	$results['CASE5_no_demote']=array('outcome'=>$r5['outcome'],'PASS'=>($r5['outcome']==='error' && ($r5['error']??'')==='no_auto_demote'));

	// --- CASE 4: canonical_changed (kitas turinys) ---
	$rows_diff=$rows; $rows_diff[0]['amount_from_g']='999.00';
	$r4=Petshop_Feeding_Importer::ingest($wpdb,$pf,array('product_id'=>$ZZ_PID,'meta'=>$meta,'rows'=>$rows_diff,
		'source_kind'=>'manufacturer_page','source_verification_status'=>'verified','source_url'=>'https://gamintojas.lt/x','source_version'=>'v2','batch_id'=>'zzb4'),true);
	$results['CASE4_canonical_changed']=array('outcome'=>$r4['outcome'],'PASS'=>($r4['outcome']==='canonical_changed_new_version'));

	// --- CASE 6: DATA_INTEGRITY (dvi needs_review su tuo paciu canonical) ---
	// isvalom, sukuriam DVI needs_review
	$ids=$wpdb->get_col("SELECT id FROM {$T} WHERE brand='ZZTEST'");
	foreach($ids as $i){ $wpdb->delete($R,array('feeding_table_id'=>$i)); $wpdb->delete($M,array('feeding_table_id'=>$i)); }
	$wpdb->query("DELETE FROM {$T} WHERE brand='ZZTEST'");
	$id_a=$mk_nr('zz_promo_a'); $id_b=$mk_nr('zz_promo_b'); // dvi skirtingi key -> skirtingi checksum
	$o['case6_debug']=array('id_a'=>$id_a,'id_b'=>$id_b,
		'nr_su_C'=>(int)$wpdb->get_var($wpdb->prepare("SELECT COUNT(*) FROM {$T} t JOIN {$M} m ON m.feeding_table_id=t.id WHERE m.product_id=%d AND t.canonical_table_hash=%s AND t.status='needs_review'",$ZZ_PID,$C)));
	$r6=Petshop_Feeding_Importer::ingest($wpdb,$pf,array('product_id'=>$ZZ_PID,'meta'=>$meta,'rows'=>$rows,
		'source_kind'=>'manufacturer_page','source_verification_status'=>'verified','source_url'=>'https://x','source_version'=>'v','batch_id'=>'zzb6'),true);
	$results['CASE6_data_integrity']=array('outcome'=>$r6['outcome'],'error'=>$r6['error']??null,'PASS'=>(($r6['error']??'')==='DATA_INTEGRITY_ERROR'));

	$o['results']=$results;
	$o['VISI_PASS']=!in_array(false,array_map(function($r){return $r['PASS'];},$results),true);

	// CLEANUP ZZTEST
	$ids=$wpdb->get_col("SELECT id FROM {$T} WHERE brand='ZZTEST'");
	foreach($ids as $i){ $wpdb->delete($R,array('feeding_table_id'=>$i)); $wpdb->delete($M,array('feeding_table_id'=>$i)); }
	$wpdb->query("DELETE FROM {$T} WHERE brand='ZZTEST'");
	$wpdb->query("DELETE FROM {$L} WHERE product_id={$ZZ_PID}");
	$o['cleanup_liko']=(int)$wpdb->get_var("SELECT COUNT(*) FROM {$T} WHERE brand='ZZTEST'");

	header('Content-Type: application/json'); echo wp_json_encode($o); exit;
});
